Here's how to handle draft persistence with .NET MAUI's app lifecycle events:

**In your `App.xaml.cs`**, hook into the lifecycle:

```csharp
public partial class App : Application
{
    public App()
    {
        InitializeComponent();
        MainPage = new AppShell();
    }

    protected override Window CreateWindow(IActivationState activationState)
    {
        var window = base.CreateWindow(activationState);

        window.Deactivated += (s, e) =>
        {
            // Save draft when app goes to background
            if (Shell.Current?.CurrentPage is NotePage page)
                page.SaveDraft();
        };

        window.Resumed += (s, e) =>
        {
            // Restore draft when app returns
            if (Shell.Current?.CurrentPage is NotePage page)
                page.RestoreDraft();
        };

        return window;
    }
}
```

**In your `NotePage.xaml.cs`**:

```csharp
public partial class NotePage : ContentPage
{
    private const string DraftKey = "note_draft";

    public NotePage()
    {
        InitializeComponent();
        RestoreDraft();
    }

    public void SaveDraft()
    {
        Preferences.Set(DraftKey, NoteEditor.Text ?? string.Empty);
    }

    public void RestoreDraft()
    {
        if (Preferences.ContainsKey(DraftKey))
            NoteEditor.Text = Preferences.Get(DraftKey, string.Empty);
    }

    // Call this when the user explicitly saves/discards
    public void ClearDraft()
    {
        Preferences.Remove(DraftKey);
    }
}
```

**Key points:**

- `Preferences` stores small strings in platform-native storage (SharedPreferences on Android, NSUserDefaults on iOS)
- `Window.Deactivated` fires when the app loses focus; `Window.Resumed` fires on return
- Clear the draft after the user intentionally saves or discards the note
- For large text, consider writing to `FileSystem.AppDataDirectory` instead of `Preferences`
